class Solution(object):
    def calculateScore(self, instructions, values):
        n = len(instructions)
        visited = set()
        score = 0
        i = 0
        while 0 <= i < n and i not in visited:
            visited.add(i)
            if instructions[i] == 'add':
                score += values[i]
                i += 1
            else:
                i += values[i]
        return score
